const db = require('./db');

function getAllReviews() {
  return db.prepare('SELECT * FROM reviews ORDER BY created_at DESC').all();
}

function getReviewsByProduct(productId) {
  return db.prepare('SELECT * FROM reviews WHERE product_id = ? ORDER BY created_at DESC').all(productId);
}

function createReview({ product_id, user_id, rating, comment }) {
  const result = db.prepare(
    'INSERT INTO reviews (product_id, user_id, rating, comment) VALUES (?, ?, ?, ?)'
  ).run(product_id, user_id, rating, comment);
  return { id: result.lastInsertRowid };
}

module.exports = { getAllReviews, getReviewsByProduct, createReview };

