import React, { useState, useEffect } from 'react';

const STAR = String.fromCharCode(9733);
const EMPTY_STAR = String.fromCharCode(9734);

export default function AddARatingsAndReviewsSystem() {
  const [reviews, setReviews] = useState([]);
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState('');
  const [status, setStatus] = useState('');

  async function loadReviews() {
    try {
      const data = await fetch('/api/add-a-ratings-and-reviews-system').then(r => r.json());
      setReviews(Array.isArray(data) ? data : []);
    } catch {
      setReviews([]);
    }
  }

  useEffect(() => {
    loadReviews();
  }, []);

  async function submit(e) {
    e.preventDefault();
    setStatus('Submitting...');
    try {
      const res = await fetch('/api/add-a-ratings-and-reviews-system', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ product_id: 1, user_id: 1, rating, comment })
      });
      if (!res.ok) throw new Error('Request failed');
      setComment('');
      setStatus('Review submitted');
      await loadReviews();
    } catch {
      setStatus('Error submitting review');
    }
  }

  return (
    <div style={{ fontFamily: 'Inter, sans-serif', color: '#0f172a' }}>
      <form onSubmit={submit} style={{ display: 'grid', gap: 12, maxWidth: 460 }}>
        <div style={{ fontWeight: 800, fontSize: 16 }}>Ratings and Reviews</div>
        <div style={{ display: 'flex', gap: 4 }}>
          {[1, 2, 3, 4, 5].map(star => (
            <button
              key={star}
              type="button"
              onClick={() => setRating(star)}
              style={{
                border: 'none',
                background: 'transparent',
                color: star <= rating ? '#f59e0b' : '#cbd5e1',
                fontSize: 26,
                cursor: 'pointer',
                lineHeight: 1,
              }}
              aria-label={star + ' stars'}
            >
              {STAR}
            </button>
          ))}
        </div>
        <textarea
          value={comment}
          onChange={e => setComment(e.target.value)}
          placeholder="Share what you thought of this product..."
          rows={3}
          style={{ padding: 10, border: '1px solid #e2e8f0', borderRadius: 8, fontFamily: 'inherit', color: '#0f172a' }}
        />
        <button type="submit" style={{ justifySelf: 'start', padding: '8px 16px', background: '#2563eb', color: '#fff', border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer' }}>
          Submit Review
        </button>
        {status && <div style={{ fontSize: 12, color: status.startsWith('Error') ? '#dc2626' : '#16a34a' }}>{status}</div>}
      </form>

      <div style={{ display: 'grid', gap: 8, marginTop: 18 }}>
        {reviews.length === 0 && <div style={{ fontSize: 13, color: '#94a3b8' }}>No reviews yet.</div>}
        {reviews.map(review => (
          <div key={review.id} style={{ padding: 12, border: '1px solid #e2e8f0', borderRadius: 10, background: '#fff' }}>
            <div style={{ color: '#f59e0b', letterSpacing: 1 }}>{STAR.repeat(review.rating)}{EMPTY_STAR.repeat(5 - review.rating)}</div>
            <div style={{ marginTop: 4, fontSize: 13, color: '#334155' }}>{review.comment || 'No comment'}</div>
          </div>
        ))}
      </div>
    </div>
  );
}
